"use strict";parserFactory.register("novelshub.org",()=>new NovelshubParser);class NovelshubParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.mt-4");return(util.hyperlinksToChapterList(t)||[]).reverse().map((e,t)=>Object.assign({},e,{title:`Chapter ${t+1}`}))}findContent(e){return e.querySelector("div.p-6")}extractTitleImpl(e){return e.querySelector("h1.text-2xl")}extractAuthor(e){let t=e.querySelector("div.flex:nth-child(3) > div:nth-child(2) > p:nth-child(1)");return t?.textContent??super.extractAuthor(e)}extractDescription(e){var t=e.querySelector("meta[name='description']")?.getAttribute("content");return t.trim()}findChapterTitle(e){return e.querySelector("meta[property='og:title']")?.getAttribute("content")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"article section")}}